import { supabaseServer } from "@/lib/supabaseServer";

function formatMoney(value: number) {
  return new Intl.NumberFormat("es-MX", {
      style: "currency",
          currency: "MXN",
              maximumFractionDigits: 2,
                }).format(value);
                }

                function formatDate(value: string | null) {
                  if (!value) return "N/D";
                    try {
                        return new Date(value).toLocaleString();
                          } catch {
                              return value;
                                }
                                }

                                export default async function AdminPage() {
                                  const supabase = await supabaseServer();

                                    const { count: users } = await supabase
                                        .from("profiles")
                                            .select("*", { count: "exact", head: true });

                                              const { count: products } = await supabase
                                                  .from("products")
                                                      .select("*", { count: "exact", head: true });

                                                        const { count: orders } = await supabase
                                                            .from("orders")
                                                                .select("*", { count: "exact", head: true });

                                                                  const { count: tickets } = await supabase
                                                                      .from("support_tickets")
                                                                          .select("*", { count: "exact", head: true });

                                                                            const { data: recentUsers } = await supabase
                                                                                .from("profiles")
                                                                                    .select("*")
                                                                                        .order("created_at", { ascending: false })
                                                                                            .limit(5);

                                                                                              return (
                                                                                                  <main
                                                                                                        style={{
                                                                                                                padding: "40px",
                                                                                                                        color: "white",
                                                                                                                                maxWidth: "1100px",
                                                                                                                                        margin: "0 auto",
                                                                                                                                              }}
                                                                                                                                                  >
                                                                                                                                                        <h1 style={{ fontSize: "32px", marginBottom: "10px" }}>
                                                                                                                                                                Panel de administración
                                                                                                                                                                      </h1>

                                                                                                                                                                            <p style={{ opacity: 0.7, marginBottom: "30px" }}>
                                                                                                                                                                                    Control total de usuarios, productos, ventas, soporte y operación
                                                                                                                                                                                            interna de LinkStream.
                                                                                                                                                                                                  </p>

                                                                                                                                                                                                        {/* BOTONES ADMIN */}
                                                                                                                                                                                                              <div
                                                                                                                                                                                                                      style={{
                                                                                                                                                                                                                                marginBottom: "30px",
                                                                                                                                                                                                                                          display: "flex",
                                                                                                                                                                                                                                                    gap: "12px",
                                                                                                                                                                                                                                                              flexWrap: "wrap",
                                                                                                                                                                                                                                                                      }}
                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                    <a
                                                                                                                                                                                                                                                                                              href="/admin/users"
                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                    padding: "12px 20px",
                                                                                                                                                                                                                                                                                                                                background: "linear-gradient(135deg,#6d5cff,#4b7cff)",
                                                                                                                                                                                                                                                                                                                                            borderRadius: "12px",
                                                                                                                                                                                                                                                                                                                                                        color: "white",
                                                                                                                                                                                                                                                                                                                                                                    fontWeight: "600",
                                                                                                                                                                                                                                                                                                                                                                                textDecoration: "none",
                                                                                                                                                                                                                                                                                                                                                                                          }}
                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                            👥 Gestionar usuarios
                                                                                                                                                                                                                                                                                                                                                                                                                    </a>

                                                                                                                                                                                                                                                                                                                                                                                                                            <a
                                                                                                                                                                                                                                                                                                                                                                                                                                      href="/admin"
                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                            padding: "12px 20px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background: "#0f172a",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    borderRadius: "12px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                color: "white",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            fontWeight: "600",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        textDecoration: "none",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    border: "1px solid rgba(255,255,255,0.1)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                📊 Panel principal
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </a>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* ESTADÍSTICAS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            display: "grid",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                gap: "20px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          marginBottom: "40px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <Stat title="Usuarios" value={users ?? 0} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Stat title="Productos" value={products ?? 0} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <Stat title="Órdenes" value={orders ?? 0} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Stat title="Tickets soporte" value={tickets ?? 0} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* USUARIOS RECIENTES */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <section style={{ marginBottom: "40px" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h2 style={{ fontSize: "22px", marginBottom: "10px" }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Usuarios recientes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </h2>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {recentUsers?.length ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      recentUsers.map((u) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                key={u.id}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              padding: "12px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              border: "1px solid rgba(255,255,255,0.1)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              borderRadius: "10px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              marginBottom: "10px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>{u.email}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div style={{ opacity: 0.7 }}>Rol: {u.role}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ opacity: 0.6 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Registro: {formatDate(u.created_at)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p style={{ opacity: 0.6 }}>No hay usuarios todavía.</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function Stat({ title, value }: { title: string; value: number }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                padding: "20px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        borderRadius: "14px",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                border: "1px solid rgba(255,255,255,0.1)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background: "rgba(255,255,255,0.03)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ opacity: 0.7 }}>{title}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div style={{ fontSize: "26px", fontWeight: "600" }}>{value}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }